// SSIContentFilterWrapper.java - Response wrapper for content inspection
package com.example.security.filters;

import javax.servlet.http.*;
import java.io.*;

public class SSIContentFilterWrapper extends HttpServletResponseWrapper {

    private StringWriter capturedContent = new StringWriter();
    private PrintWriter writer;
    private boolean isText = false;

    public SSIContentFilterWrapper(HttpServletResponse response) {
        super(response);
    }

    @Override
    public void setContentType(String type) {
        super.setContentType(type);
        isText = type != null && (type.contains("text/") || type.contains("application/json"));
    }

    @Override
    public PrintWriter getWriter() throws IOException {
        if (isText) {
            if (writer == null) {
                writer = new PrintWriter(capturedContent);
            }
            return writer;
        }
        return super.getWriter();
    }

    public String getCapturedContent() {
        if (writer != null) {
            writer.flush();
            return capturedContent.toString();
        }
        return null;
    }
}
