Allowing user-controlled template inclusion is extremely dangerous and can lead to Server-Side Include (SSI) injection or Server-Side Template Injection (SSTI). Attackers can execute arbitrary code, read sensitive files, or take over your server entirely.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');
const ejs = require('ejs');

const app = express();

// DANGEROUS: User controls which template to include
app.get('/page', (req, res) => {
  const templateName = req.query.template || 'default';

  // Vulnerable: No validation of template path
  const templatePath = path.join(__dirname, 'templates', templateName + '.ejs');

  // Directly reading and rendering user-specified template
  const template = fs.readFileSync(templatePath, 'utf-8');

  // Even worse: User data directly interpolated
  const userData = req.query.data || '';
  const html = ejs.render(template, { content: userData });

  res.send(html);
});

// DANGEROUS: SSI-style dynamic includes
app.get('/include', (req, res) => {
  let content = req.query.content || '';

  // Processing SSI-like directives from user input
  content = content.replace(/<!--#include file="([^"]+)"-->/g, (match, file) => {
    // Vulnerable: Includes any file the user specifies
    return fs.readFileSync(file, 'utf-8');
  });

  res.send(content);
});

app.listen(3000);
```

**Attack Payload**:
```text
# Path traversal to read sensitive files
GET /page?template=../../../etc/passwd%00

# SSI injection to read arbitrary files
GET /include?content=<!--%23include%20file="/etc/passwd"-->

# Template injection for RCE in EJS
GET /page?data=<%= process.mainModule.require('child_process').execSync('id').toString() %>
```

**Why This Is Dangerous**:
- User controls file paths, enabling directory traversal attacks
- SSI directives are processed from untrusted input
- Template engines can execute arbitrary JavaScript when user controls template content
- No input validation or sanitization on file paths or template names
- Attackers can read /etc/passwd, environment variables, or execute system commands

**SECURE VERSION**:

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');
const ejs = require('ejs');
const validator = require('validator');

const app = express();

// Whitelist of allowed templates
const ALLOWED_TEMPLATES = new Set([
  'home',
  'about',
  'contact',
  'products',
  'services'
]);

// Secure template directory (absolute path)
const TEMPLATE_DIR = path.resolve(__dirname, 'templates');

// SECURE: Whitelist-based template selection
app.get('/page', (req, res) => {
  const templateName = req.query.template || 'home';

  // Validate against whitelist
  if (!ALLOWED_TEMPLATES.has(templateName)) {
    console.warn(`Blocked invalid template request: ${templateName}`);
    return res.status(400).send('Invalid template');
  }

  // Construct safe path and verify it's within template directory
  const templatePath = path.join(TEMPLATE_DIR, `${templateName}.ejs`);
  const normalizedPath = path.resolve(templatePath);

  if (!normalizedPath.startsWith(TEMPLATE_DIR)) {
    console.error(`Path traversal attempt detected: ${templateName}`);
    return res.status(403).send('Access denied');
  }

  try {
    // Render with escaped user data only
    const userData = validator.escape(req.query.data || '');
    const html = ejs.renderFile(templatePath, { 
      content: userData 
    }, { 
      // Disable dangerous features
      rmWhitespace: true
    });

    res.send(html);
  } catch (err) {
    console.error('Template render error:', err.message);
    res.status(500).send('Error loading page');
  }
});

// SECURE: No SSI processing - static content only
app.get('/content/:slug', (req, res) => {
  const slug = req.params.slug;

  // Alphanumeric only, no special characters
  if (!/^[a-z0-9-]+$/.test(slug)) {
    return res.status(400).send('Invalid content identifier');
  }

  const contentPath = path.join(TEMPLATE_DIR, 'content', `${slug}.html`);
  const normalizedPath = path.resolve(contentPath);

  // Verify path is within allowed directory
  const allowedContentDir = path.resolve(TEMPLATE_DIR, 'content');
  if (!normalizedPath.startsWith(allowedContentDir)) {
    return res.status(403).send('Access denied');
  }

  // Send static file without processing
  res.sendFile(normalizedPath);
});

app.listen(3000);
```

**Key Security Controls**:
- **Whitelist validation**: Only pre-approved template names are allowed, blocking arbitrary file access
- **Path normalization**: Uses path.resolve() to prevent directory traversal attacks like ../../../etc/passwd
- **Input sanitization**: User data is HTML-escaped before template interpolation
- **No SSI processing**: Removed dangerous server-side include directive processing entirely

When you need dynamic templates from content editors, you must use a sandboxed template engine that prevents code execution. Never allow raw template syntax from untrusted sources. Here's a production-ready approach:

**PRODUCTION PATTERN**:

