  new nunjucks.FileSystemLoader('templates', {
    noCache: process.env.NODE_ENV !== 'production'
  }),
  {
    autoescape: true,
    throwOnUndefined: true,
    trimBlocks: true,
    lstripBlocks: true
  }
);

