const BLOCKED_GLOBALS = ['require', 'process', 'global', '__dirname', '__filename'];

// Custom sandboxed template processor
class SecureTemplateProcessor {
  constructor() {
    this.allowedVariables = new Set([
      'title', 'content', 'author', 'date', 'category', 'tags'
    ]);

    this.allowedFilters = new Set([
      'capitalize', 'lower', 'upper', 'trim', 'truncate', 'wordcount'
    ]);

    // Dangerous patterns to block
    this.dangerousPatterns = [
      /\{\%\s*include/gi,
      /\{\%\s*import/gi,
      /\{\%\s*extends/gi,
      /\{\%\s*raw/gi,
      /\{\%\s*call/gi,
      /\{\{\s*[\w]+\s*\(/gi,  // Function calls
      /\{\{\s*constructor/gi,
      /\{\{\s*__proto__/gi,
      /\{\{\s*prototype/gi,
      /process\./gi,
      /require\s*\(/gi,
      /child_process/gi,
      /\beval\b/gi,
      /Function\s*\(/gi
    ];
  }

  validateTemplate(templateContent) {
    const errors = [];

    // Check for dangerous patterns
    for (const pattern of this.dangerousPatterns) {
      if (pattern.test(templateContent)) {
        errors.push(`Blocked dangerous pattern: ${pattern.source}`);
      }
    }

    // Limit template complexity
    const variableMatches = templateContent.match(/\{\{[^}]+\}\}/g) || [];
    if (variableMatches.length > 50) {
      errors.push('Too many template variables (max 50)');
    }

    const blockMatches = templateContent.match(/\{\%[^%]+\%\}/g) || [];
    if (blockMatches.length > 20) {
      errors.push('Too many template blocks (max 20)');
    }

    return {
      valid: errors.length === 0,
      errors
    };
  }

  sanitizeContext(userContext) {
    const safeContext = {};

    for (const [key, value] of Object.entries(userContext)) {
      // Only allow whitelisted variables
      if (!this.allowedVariables.has(key)) {
        continue;
      }

      // Sanitize string values
      if (typeof value === 'string') {
        safeContext[key] = DOMPurify.sanitize(value, {
          ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br'],
          ALLOWED_ATTR: ['href']
        });
      } else if (typeof value === 'number') {
        safeContext[key] = value;
      } else if (Array.isArray(value)) {
        safeContext[key] = value
          .filter(v => typeof v === 'string' || typeof v === 'number')
          .slice(0, 100);
      }
    }

    return safeContext;
  }

  async render(templateId, userContext, requestInfo) {
    const startTime = Date.now();

    // Validate template ID format
    if (!/^[a-f0-9]{32}$/.test(templateId)) {
      throw new Error('Invalid template identifier');
    }

