# Environment variable disclosure
username=<!--#printenv -->
```

**Why This Is Dangerous**:
- SSI exec directive allows arbitrary command execution on the server
- User-controlled input can inject SSI directives for file inclusion
- Default SSI configuration often enables dangerous features
- SSI processes content after servlet output, bypassing application-level controls
- Attackers can read sensitive files like /etc/passwd, configuration files, or source code

**SECURE VERSION**:

```java
import javax.servlet.*;
import javax.servlet.http.*;
import java.io.*;
import java.util.regex.Pattern;
import org.owasp.encoder.Encode;

public class SecureDynamicContentServlet extends HttpServlet {

    // Whitelist of allowed template names
    private static final Pattern SAFE_TEMPLATE_PATTERN = Pattern.compile("^[a-zA-Z0-9_-]+$");
    private static final String[] ALLOWED_TEMPLATES = {"header", "footer", "sidebar", "menu"};

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String username = request.getParameter("username");
        String templateName = request.getParameter("template");

        // SECURE: Strict input validation
        if (username == null || username.length() > 50) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid username");
            return;
        }

        // SECURE: Whitelist validation for template names
        if (!isValidTemplate(templateName)) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid template");
            return;
        }

        response.setContentType("text/html;charset=UTF-8");
        response.setHeader("X-Content-Type-Options", "nosniff");
        PrintWriter out = response.getWriter();

        out.println("<html><body>");
        // SECURE: HTML encode all user input
        out.println("<h1>Welcome, " + Encode.forHtml(username) + "</h1>");

        // SECURE: Use safe template inclusion via application logic
        includeTemplate(out, templateName);

        out.println("</body></html>");
    }

    private boolean isValidTemplate(String template) {
        if (template == null || !SAFE_TEMPLATE_PATTERN.matcher(template).matches()) {
            return false;
        }
        for (String allowed : ALLOWED_TEMPLATES) {
            if (allowed.equals(template)) {
                return true;
            }
        }
        return false;
    }

    private void includeTemplate(PrintWriter out, String templateName) throws IOException {
        // SECURE: Load template from classpath, not SSI
        String templatePath = "/templates/" + templateName + ".html";
        try (InputStream is = getServletContext().getResourceAsStream(templatePath)) {
            if (is != null) {
                BufferedReader reader = new BufferedReader(new InputStreamReader(is));
                String line;
                while ((line = reader.readLine()) != null) {
                    out.println(line);
                }
            }
        }
    }
}
```

**Key Security Controls**:
- **Disable SSI entirely**: Remove SSI servlet from web.xml if not absolutely required
- **Strict input validation**: Whitelist allowed values, reject anything suspicious
- **HTML encoding**: Use OWASP Encoder to prevent SSI directive injection
- **Application-level templating**: Use secure template engines (Thymeleaf, FreeMarker) instead of SSI

If you must maintain SSI for legacy compatibility, you need multiple layers of protection. The key is to disable dangerous directives, restrict what can be included, and ensure user input never reaches SSI-processed content.

**PRODUCTION PATTERN**:

```java
import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.WebFilter;
import java.io.*;
import java.util.regex.Pattern;
import java.util.logging.Logger;

@WebFilter(urlPatterns = "*.shtml")
public class SSISecurityFilter implements Filter {

    private static final Logger AUDIT_LOG = Logger.getLogger("security.ssi");

    // Pattern to detect SSI injection attempts
    private static final Pattern SSI_PATTERN = Pattern.compile(
        "<!--\\s*#\\s*(include|exec|echo|config|flastmod|fsize|printenv|set|if|elif|else|endif)",
        Pattern.CASE_INSENSITIVE
    );

    // Pattern to detect path traversal
    private static final Pattern PATH_TRAVERSAL = Pattern.compile(
        "\\.\\./|\\.\\.\\\\|%2e%2e|%252e",
        Pattern.CASE_INSENSITIVE
    );

    @Override
    public void init(FilterConfig filterConfig) throws ServletException {
        AUDIT_LOG.info("SSI Security Filter initialized");
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
            throws IOException, ServletException {

        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        // Check all request parameters for SSI injection
        for (String paramName : httpRequest.getParameterMap().keySet()) {
            String[] values = httpRequest.getParameterValues(paramName);
            for (String value : values) {
                if (containsSSIDirective(value) || containsPathTraversal(value)) {
                    AUDIT_LOG.warning(String.format(
                        "BLOCKED SSI injection attempt: IP=%s, URI=%s, Param=%s, Value=%s",
                        getClientIP(httpRequest),
                        httpRequest.getRequestURI(),
                        paramName,
                        sanitizeLogValue(value)
                    ));
                    httpResponse.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid request");
                    return;
                }
            }
        }

        // Wrap response to sanitize output before SSI processing
        SSISanitizingResponseWrapper wrappedResponse = 
            new SSISanitizingResponseWrapper(httpResponse);

        chain.doFilter(request, wrappedResponse);

        // Write sanitized content
        String content = wrappedResponse.getCapturedContent();
        response.getWriter().write(content);
    }

    private boolean containsSSIDirective(String value) {
        return value != null && SSI_PATTERN.matcher(value).find();
    }

    private boolean containsPathTraversal(String value) {
        return value != null && PATH_TRAVERSAL.matcher(value).find();
    }

    private String getClientIP(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String sanitizeLogValue(String value) {
        if (value.length() > 100) {
            return value.substring(0, 100) + "[TRUNCATED]";
        }
        return value.replaceAll("[\\r\\n]", "_");
    }

    @Override
    public void destroy() {}
}

// Response wrapper to sanitize content before SSI processing
class SSISanitizingResponseWrapper extends HttpServletResponseWrapper {

    private CharArrayWriter charWriter = new CharArrayWriter();
    private PrintWriter writer = new PrintWriter(charWriter);

    private static final Pattern DANGEROUS_SSI = Pattern.compile(
        "<!--\\s*#\\s*(exec|config|set)",
        Pattern.CASE_INSENSITIVE
    );

    public SSISanitizingResponseWrapper(HttpServletResponse response) {
        super(response);
    }

    @Override
    public PrintWriter getWriter() {
        return writer;
    }

    public String getCapturedContent() {
        writer.flush();
        String content = charWriter.toString();

        // Remove any dangerous SSI directives from output
        content = DANGEROUS_SSI.matcher(content).replaceAll("<!-- [REMOVED] ");

        return content;
    }
}
```

